  data.conference_name = confNameEl ? confNameEl.textContent.trim() : null;

  // Acronym - extract from title or name
  data.acronym = "ICITRI";

  // Location
  const locationEl = document.querySelector('header .container p');
  data.location = locationEl ? locationEl.textContent.trim() : null;

  // Conference dates
  const confDateEl = document.querySelector('table tbody tr:last-child td:last-child');
  data.conference_dates = confDateEl ? confDateEl.textContent.trim() : null;

  // Important dates - find the table
  const dateTable = document.querySelector('#important-dates').nextElementSibling;
  const rows = dateTable.querySelectorAll('tbody tr');

  // Submission deadline
  const submissionRow = rows[0];
  const submissionText = submissionRow.querySelector('td:last-child').textContent.trim();
  data.submission_deadline = submissionText.replace(/extend/g, '').trim();

  // Notification date
  const notificationRow = rows[1];
  const notificationText = notificationRow.querySelector('td:last-child').textContent.trim();
  data.notification_date = notificationText.replace(/extend/g, '').trim();

  // Topics - extract from tracks section
  const topics = [];

  // Informatics Track
  const informaticsTrack = document.querySelector('#tracks').parentElement.querySelectorAll('.accordion-item')[0];
  const informaticsTopics = informaticsTrack.querySelectorAll('ul li');
  informaticsTopics.forEach(li => topics.push(li.textContent.trim()));

  // Try to get other tracks by clicking or finding them
  const allAccordions = document.querySelectorAll('.accordion-item');
  allAccordions.forEach((accordion, idx) => {
    if (idx > 0) { // Skip first one as we already got it
      const heading = accordion.querySelector('h4');
      if (heading) {
        const trackName = heading.textContent.trim();
        topics.push(trackName);
      }
    }
  });

  data.topics = topics;

  // Submission URL
  const registerLink = document.querySelector('a[href*="edas.info"]');
  data.submission_url = registerLink ? registerLink.href : null;

  // Get XPath for the important dates section (the table containing dates)
  data.source_xpath = getXPath(dateTable);

  return data;
