    const submissionText = submissionCell.textContent;
    // Extract the extended date (30 June 2026)
    const match = submissionText.match(/(\d+\s+\w+\s+\d{4})\s*extend/);
    if (match) {
      data.submission_deadline = match[1];
    } else {
      // Fallback to first date
      const firstMatch = submissionText.match(/(\d+\s+\w+\s+\d{4})/);
      data.submission_deadline = firstMatch ? firstMatch[1] : null;
    }
  }

  // Notification date - get the extended date
  if (rows.length > 1) {
